// 읽기 난이도 3단계(원문 / 쉬운말 / 쉽게읽기) 본문 데이터.
// 원본 prototype_integrated.html 의 setReadLevel 스크립트를 그대로 이식했습니다.

// 본문 안 수치 하이라이트(.hk-stat) span 을 생성하는 헬퍼.
// 팝오버 내부 마크업은 initHkStatHighlight 엔진이 data-* 속성으로부터 만들어 붙입니다.
function stat(num, label, unit, basis, source, def) {
  return (
    '<span class="hk-stat" tabindex="0" role="button" aria-haspopup="true" ' +
    'data-label="' + label + '" data-unit="' + unit + '" data-basis="' + basis + '" ' +
    'data-source="' + source + '" data-def="' + def + '" data-source-url="#">' + num + '</span>'
  );
}

